import numpy as np

def select_next_node(cur_truck_pos, depot_pos, all_truck_pos, unvisited_customers, current_time, truck_speed, time_windows):
    def calculate_travel_time(pos1, pos2, speed):
        return np.linalg.norm(pos1 - pos2) / speed

    def penalty(time, window):
        if time < window[0]:
            return (window[0] - time) * 2  # penalty for waiting
        elif time > window[1]:
            return (time - window[1]) * 5  # penalty for missing window
        else:
            return 0

    best_node = None
    min_cost = float('inf')

    for i, customer_pos in enumerate(unvisited_customers):
        travel_time = calculate_travel_time(cur_truck_pos, customer_pos, truck_speed)
