        # Consider proximity of other trucks to the same customer
        for other_truck_pos in all_truck_pos:
            if not np.array_equal(other_truck_pos, cur_truck_pos):
                other_travel_time = calculate_travel_time(other_truck_pos, customer_pos, truck_speed)
                if other_travel_time < travel_time:
                    cost += (travel_time - other_travel_time)

        if cost < min_cost:
            min_cost = cost
            best_node = i

    return best_node

